33	namespace Quartz.Core;
34	
35	/// <summary>
36	/// JobRunShell instances are responsible for providing the 'safe' environment
37	/// for <see cref="IJob" /> s to run in, and for performing all of the work of
38	/// executing the <see cref="IJob" />, catching ANY thrown exceptions, updating
39	/// the <see cref="ITrigger" /> with the <see cref="IJob" />'s completion code,
40	/// etc.
41	/// <para>
42	/// A <see cref="JobRunShell" /> instance is created by a <see cref="IJobRunShellFactory" />
43	/// on behalf of the <see cref="QuartzSchedulerThread" /> which then runs the
44	/// shell in a thread from the configured thread pool when the
45	/// scheduler determines that a <see cref="IJob" /> has been triggered.
46	/// </para>
47	/// </summary>
48	/// <seealso cref="IJobRunShellFactory" />
49	/// <seealso cref="QuartzSchedulerThread" />
50	/// <seealso cref="IJob" />
51	/// <seealso cref="ITrigger" />
52	/// <author>James House</author>
53	/// <author>Marko Lahma (.NET)</author>
54	public class JobRunShell : SchedulerListenerSupport
55	{
56	    private readonly ILogger<JobRunShell> logger;
57	
58	    private JobExecutionContextImpl? jec;
59	    private QuartzScheduler? qs;
60	    private readonly IScheduler scheduler;
61	    private readonly TriggerFiredBundle firedTriggerBundle;
62	
63	    /// <summary>
64	    /// Create a JobRunShell instance with the given settings.
65	    /// </summary>
66	    /// <param name="scheduler">The <see cref="IScheduler" /> instance that should be made
67	    /// available within the <see cref="IJobExecutionContext" />.</param>
68	    /// <param name="bundle"></param>
69	    public JobRunShell(IScheduler scheduler, TriggerFiredBundle bundle)
70	    {
71	        this.scheduler = scheduler;
72	        firedTriggerBundle = bundle;
73	        logger = LogProvider.CreateLogger<JobRunShell>();
74	    }
75	
76	    public override ValueTask SchedulerShuttingdown(CancellationToken cancellationToken = default)
77	    {
78	        RequestShutdown();
79	        return default;
80	    }
81	
82	    /// <summary>
83	    /// Initializes the job execution context with given scheduler and bundle.
84	    /// </summary>
85	    /// <param name="sched">The scheduler.</param>
86	    /// <param name="cancellationToken">The cancellation instruction.</param>
87	    public virtual async Task Initialize(
88	        QuartzScheduler sched,
89	        CancellationToken cancellationToken = default)
90	    {
91	        qs = sched;
92	
93	        IJob job;
94	
95	        try
96	        {
97	            job = sched.JobFactory.NewJob(firedTriggerBundle, scheduler);
98	        }
99	        catch (SchedulerException se)
100	        {
101	            await sched.NotifySchedulerListenersError($"An error occurred instantiating job to be executed. job= '{firedTriggerBundle.JobDetail.Key}'", se, cancellationToken).ConfigureAwait(false);
102	            throw;
103	        }
104	        catch (Exception e)
105	        {
106	            SchedulerException se = new SchedulerException($"Problem instantiating type '{firedTriggerBundle.JobDetail.JobType.FullName}: {e.Message}'", e);
107	            await sched.NotifySchedulerListenersError($"An error occurred instantiating job to be executed. job= '{firedTriggerBundle.JobDetail.Key}, message={e.Message}'", se, cancellationToken).ConfigureAwait(false);
108	            throw se;
109	        }
110	
111	        jec = new JobExecutionContextImpl(scheduler, firedTriggerBundle, job);
112	    }
113	
114	    /// <summary>
115	    /// Requests the Shutdown.
116	    /// </summary>
117	    public virtual void RequestShutdown()
118	    {
119	    }
120	
121	    /// <summary>
122	    /// This method has to be implemented in order that starting of the thread causes the object's
123	    /// run method to be called in that separately executing thread.
124	    /// </summary>
125	    /// <param name="cancellationToken">The cancellation instruction.</param>
126	    public virtual async Task Run(CancellationToken cancellationToken = default)
127	    {
128	        Context.CallerId.Value = Guid.NewGuid();
129	        qs!.AddInternalSchedulerListener(this);
130	
131	        IJob job = jec!.jobInstance;
132	
133	        try
134	        {
135	            IOperableTrigger trigger = (IOperableTrigger) jec.Trigger;
136	            IJobDetail jobDetail = jec.JobDetail;
137	            do
138	            {
139	                JobExecutionException? jobExEx = null;
140	
141	                try
142	                {
143	                    Begin();
144	                }
145	                catch (SchedulerException se)
146	                {
147	                    string msg = $"Error executing Job {jec.JobDetail.Key}: couldn't begin execution.";
148	                    await qs.NotifySchedulerListenersError(msg, se, cancellationToken).ConfigureAwait(false);
149	                    await qs.NotifyJobStoreJobComplete(trigger, jobDetail, SchedulerInstruction.NoInstruction, cancellationToken).ConfigureAwait(false);
150	                    break;
151	                }
152	
153	                // notify job & trigger listeners...
154	                SchedulerInstruction instCode;
155	                try
156	                {
157	                    if (!await NotifyListenersBeginning(jec, cancellationToken).ConfigureAwait(false))
158	                    {
159	                        await qs.NotifyJobStoreJobComplete(trigger, jobDetail, SchedulerInstruction.NoInstruction, cancellationToken).ConfigureAwait(false);
160	                        break;
161	                    }
162	                }
163	                catch (VetoedException)
164	                {
165	                    try
166	                    {
167	                        instCode = trigger.ExecutionComplete(jec, result: null);
168	                        await qs.NotifyJobStoreJobVetoed(trigger, jobDetail, instCode, cancellationToken).ConfigureAwait(false);
169	
170	                        // Even if trigger got vetoed, we still needs to check to see if it's the trigger's finalized run or not.
171	                        if (!trigger.GetMayFireAgain())
172	                        {
173	                            await qs.NotifySchedulerListenersFinalized(jec.Trigger, cancellationToken).ConfigureAwait(false);
174	                        }
175	                        Complete(successfulExecution: true);
176	                    }
177	                    catch (SchedulerException se)
178	                    {
179	                        string msg = $"Error during veto of Job {jec.JobDetail.Key}: couldn't finalize execution.";
180	                        await qs.NotifySchedulerListenersError(msg, se, cancellationToken).ConfigureAwait(false);
181	                    }
182	                    break;
183	                }
184	
185	                if (logger.IsEnabled(LogLevel.Debug))
186	                {
187	                    logger.LogDebug("Calling Execute on job {JobKey}", jobDetail.Key);
188	                }
189	
190	                TimeProvider timeProvider = qs.resources.TimeProvider;
191	                long startTimestamp = timeProvider.GetTimestamp();
192	                long endTimestamp;
193	
194	                StartedActivity activity = QuartzActivitySource.StartJobExecute(jec, timeProvider.GetUtcNow());
195	                Instrumentation instrumentation = Meters.StartJobExecute(jec);
196	
197	
198	                // Execute the job
199	                try
200	                {
201	                    await job.Execute(jec).ConfigureAwait(false);
202	                    endTimestamp = timeProvider.GetTimestamp();
203	                }
204	                catch (OperationCanceledException) when (jec.CancellationToken.IsCancellationRequested)
205	                {
206	                    endTimestamp = timeProvider.GetTimestamp();
207	                    logger.LogInformation("Job {JobDetailKey} was cancelled", jobDetail.Key);
208	                }
209	                catch (JobExecutionException jee)
210	                {
211	                    endTimestamp = timeProvider.GetTimestamp();
212	                    jee.JobDetail = jobDetail;
213	                    jobExEx = jee;
214	                    logger.LogError(jee, "Job {JobDetailKey} threw a JobExecutionException: ", jobDetail.Key);
215	                }
216	                catch (Exception e)
217	                {
218	                    endTimestamp = timeProvider.GetTimestamp();
219	                    logger.LogError(e, "Job {JobDetailKey} threw an unhandled Exception: ", jobDetail.Key);
220	                    SchedulerException se = new JobExecutionProcessException(jec, e);
221	                    await qs.NotifySchedulerListenersError($"Job {jec.JobDetail.Key} threw an exception.", se, cancellationToken).ConfigureAwait(false);
222	                    jobExEx = new JobExecutionException(se, refireImmediately: false);
223	                    jobExEx.JobDetail = jobDetail;
224	                }
225	
226	                jec.JobRunTime = timeProvider.GetElapsedTime(startTimestamp, endTimestamp);
227	
228	                activity.Stop(timeProvider.GetUtcNow(), jobExEx);
229	                instrumentation.EndJobExecute(jec.JobRunTime, jobExEx);
230	
231	                // notify all job listeners
232	                if (!await NotifyJobListenersComplete(qs, jec, jobExEx, cancellationToken).ConfigureAwait(false))
233	                {
234	                    var failureInstCode = SchedulerInstruction.NoInstruction;
235	
236	                    // update the trigger to determine the correct instruction, even when listener notification fails
237	                    try
238	                    {
239	                        failureInstCode = trigger.ExecutionComplete(jec, jobExEx);
240	                        if (logger.IsEnabled(LogLevel.Debug))
241	                        {
242	                            logger.LogDebug("Trigger instruction : {InstCode}", failureInstCode);
243	                        }
244	                    }
245	                    catch (Exception e)
246	                    {
247	                        // If this happens, there's a bug in the trigger...
248	                        SchedulerException se = new SchedulerException("Trigger threw an unhandled exception.", e);
249	                        await qs.NotifySchedulerListenersError("Please report this error to the Quartz developers.", se, cancellationToken).ConfigureAwait(false);
250	                    }
251	
252	                    await qs.NotifyJobStoreJobComplete(trigger, jobDetail, failureInstCode, cancellationToken).ConfigureAwait(false);
253	                    break;
254	                }
255	
256	                instCode = SchedulerInstruction.NoInstruction;
257	
258	                // update the trigger
259	                try
260	                {
261	                    instCode = trigger.ExecutionComplete(jec, jobExEx);
262	                    if (logger.IsEnabled(LogLevel.Debug))
263	                    {
264	                        logger.LogDebug("Trigger instruction : {InstCode}", instCode);
265	                    }
266	                }
267	                catch (Exception e)
268	                {
269	                    // If this happens, there's a bug in the trigger...
270	                    SchedulerException se = new SchedulerException("Trigger threw an unhandled exception.", e);
271	                    await qs.NotifySchedulerListenersError("Please report this error to the Quartz developers.", se, cancellationToken).ConfigureAwait(false);
272	                }
273	
274	                // notify all trigger listeners
275	                if (!await NotifyTriggerListenersComplete(qs, jec, instCode, cancellationToken).ConfigureAwait(false))
276	                {
277	                    // Ensure finalized notification is still sent when the trigger has no next fire time,
278	                    // even if trigger listener notification failed.
279	                    try
280	                    {
281	                        if (!trigger.GetMayFireAgain())
282	                        {
283	                            await qs.NotifySchedulerListenersFinalized(jec.Trigger, cancellationToken).ConfigureAwait(false);
284	                        }
285	                    }
286	                    catch (Exception e)
287	                    {
288	                        SchedulerException se2 = new SchedulerException("Error notifying scheduler listeners of finalized trigger.", e);
289	                        await qs.NotifySchedulerListenersError("Error notifying scheduler listeners of finalized trigger.", se2, cancellationToken).ConfigureAwait(false);
290	                    }
291	
292	                    await qs.NotifyJobStoreJobComplete(trigger, jobDetail, instCode, cancellationToken).ConfigureAwait(false);
293	                    break;
294	                }
295	                // update job/trigger or re-Execute job
296	                if (instCode == SchedulerInstruction.ReExecuteJob)
297	                {
298	                    if (logger.IsEnabled(LogLevel.Debug))
299	                    {
300	                        logger.LogDebug("Rescheduling trigger to reexecute");
301	                    }
302	                    jec.IncrementRefireCount();
303	                    try
304	                    {
305	                        Complete(successfulExecution: false);
306	                    }
307	                    catch (SchedulerException se)
308	                    {
309	                        await qs.NotifySchedulerListenersError($"Error executing Job {jec.JobDetail.Key}: couldn't finalize execution.", se, cancellationToken).ConfigureAwait(false);
310	                    }
311	                    continue;
312	                }
313	
314	                try
315	                {
316	                    Complete(successfulExecution: true);
317	                }
318	                catch (SchedulerException se)
319	                {
320	                    await qs.NotifySchedulerListenersError($"Error executing Job {jec.JobDetail.Key}: couldn't finalize execution.", se, cancellationToken).ConfigureAwait(false);
321	                    continue;
322	                }
323	
324	                await qs.NotifyJobStoreJobComplete(trigger, jobDetail, instCode, cancellationToken).ConfigureAwait(false);
325	
326	                break;
327	            } while (true);
328	        }
329	        finally
330	        {
331	            qs.RemoveInternalSchedulerListener(this);
332	            await qs.JobFactory.ReturnJob(job).ConfigureAwait(false);
333	            jec.Dispose();
334	        }
335	    }
336	
337	    /// <summary>
338	    /// Runs begin procedures on this instance.
339	    /// </summary>
340	    protected virtual void Begin()
341	    {
342	    }
343	
344	    /// <summary>
345	    /// Completes the execution.
346	    /// </summary>
347	    /// <param name="successfulExecution">if set to <c>true</c> [successful execution].</param>
348	    protected virtual void Complete(bool successfulExecution)
349	    {
350	    }
351	
352	    /// <summary>
353	    /// Passivates this instance.
354	    /// </summary>
355	    public virtual void Passivate()
356	    {
357	        jec = null;
358	        qs = null;
359	    }
360	
361	    private async ValueTask<bool> NotifyListenersBeginning(
362	        JobExecutionContextImpl ctx,
363	        CancellationToken cancellationToken = default)
364	    {
365	        bool vetoed;
366	
367	        // notify all trigger listeners
368	        try
369	        {
370	            vetoed = await qs!.NotifyTriggerListenersFired(ctx, cancellationToken).ConfigureAwait(false);
371	        }
372	        catch (SchedulerException se)
373	        {
374	            var msg = $"Unable to notify TriggerListener(s) while firing trigger (Trigger and Job will NOT be fired!). trigger= {ctx.Trigger.Key} job= {ctx.JobDetail.Key}";
375	            await qs!.NotifySchedulerListenersError(msg, se, cancellationToken).ConfigureAwait(false);
376	            return false;
377	        }
378	
379	        if (vetoed)
380	        {
381	            try
382	            {
383	                using Activity? activity = QuartzActivitySource.Instance.StartActivity(OperationName.Job.Veto);
384	                activity?.EnrichFrom(ctx);
385	
386	                await qs.NotifyJobListenersWasVetoed(ctx, cancellationToken).ConfigureAwait(false);
387	            }
388	            catch (SchedulerException se)
389	            {
390	                var msg = $"Unable to notify JobListener(s) of vetoed execution while firing trigger (Trigger and Job will NOT be fired!). trigger= {ctx.Trigger.Key} job= {ctx.JobDetail.Key}";
391	                await qs.NotifySchedulerListenersError(msg, se, cancellationToken).ConfigureAwait(false);
392	            }
393	            throw new VetoedException(this);
394	        }
395	
396	        // notify all job listeners
397	        try
398	        {
399	            await qs.NotifyJobListenersToBeExecuted(ctx, cancellationToken).ConfigureAwait(false);
400	        }
401	        catch (SchedulerException se)
402	        {
403	            string msg = $"Unable to notify JobListener(s) of Job to be executed: (Job will NOT be executed!). trigger= {ctx.Trigger.Key} job= {ctx.JobDetail.Key}";
404	            await qs.NotifySchedulerListenersError(msg, se, cancellationToken).ConfigureAwait(false);
405	
406	            return false;
407	        }
408	
409	        return true;
410	    }
411	
412	    private static async ValueTask<bool> NotifyJobListenersComplete(QuartzScheduler qs,
413	        JobExecutionContextImpl ctx,
414	        JobExecutionException? jobExEx,
415	        CancellationToken cancellationToken = default)
416	    {
417	        try
418	        {
419	            await qs.NotifyJobListenersWasExecuted(ctx, jobExEx, cancellationToken).ConfigureAwait(false);
420	        }
421	        catch (SchedulerException se)
422	        {
423	            string msg = $"Unable to notify JobListener(s) of Job that was executed: (error will be ignored). trigger= {ctx.Trigger.Key} job= {ctx.JobDetail.Key}";
424	            await qs.NotifySchedulerListenersError(msg, se, cancellationToken).ConfigureAwait(false);
425	
426	            return false;
427	        }
428	
429	        return true;
430	    }
431	
432	    private static ValueTask<bool> NotifyTriggerListenersComplete(QuartzScheduler qs,
433	        JobExecutionContextImpl ctx,
434	        SchedulerInstruction instCode,
435	        CancellationToken cancellationToken = default)
436	    {
437	        // check if we can do quick path
438	        if (ctx.Trigger.GetMayFireAgain())
439	        {
440	            try
441	            {
442	                var task = qs.NotifyTriggerListenersComplete(ctx, instCode, cancellationToken);
443	                return task.IsCompletedSuccessfully ? new ValueTask<bool>(true) : DoNotify(task, qs, ctx, cancellationToken);
444	            }
445	            catch (SchedulerException se)
446	            {
447	                return NotifyError(se, qs, ctx, cancellationToken);
448	            }
449	        }
450	
451	        return NotifyAwaited(qs, ctx, instCode, cancellationToken);
452	
453	        static async ValueTask<bool> NotifyAwaited(QuartzScheduler qs,
454	            JobExecutionContextImpl ctx,
455	            SchedulerInstruction instCode,
456	            CancellationToken cancellationToken)
457	        {
458	            await DoNotify(qs.NotifyTriggerListenersComplete(ctx, instCode, cancellationToken), qs, ctx, cancellationToken).ConfigureAwait(false);
459	            await qs.NotifySchedulerListenersFinalized(ctx.Trigger, cancellationToken).ConfigureAwait(false);
460	
461	            return true;
462	        }
463	
464	        static async ValueTask<bool> DoNotify(ValueTask t,
465	            QuartzScheduler qs,
466	            JobExecutionContextImpl ctx,
467	            CancellationToken cancellationToken)
468	        {
469	            try
470	            {
471	                await t.ConfigureAwait(false);
472	                return true;
473	            }
474	            catch (SchedulerException se)
475	            {
476	                return await NotifyError(se, qs, ctx, cancellationToken).ConfigureAwait(false);
477	            }
478	        }
479	
480	        static async ValueTask<bool> NotifyError(SchedulerException se,
481	            QuartzScheduler qs,
482	            JobExecutionContextImpl ctx,
483	            CancellationToken cancellationToken)
484	        {
485	            string msg = $"Unable to notify TriggerListener(s) of Job that was executed: (error will be ignored). trigger= {ctx.Trigger.Key} job= {ctx.JobDetail.Key}";
486	            await qs.NotifySchedulerListenersError(msg, se, cancellationToken).ConfigureAwait(false);
487	            return false;
488	        }
489	    }
490	
491	    [Serializable]
492	    internal sealed class VetoedException : Exception
493	    {
494	        public VetoedException(JobRunShell shell)
495	        {
496	            EnclosingInstance = shell;
497	        }
498	
499	        public JobRunShell EnclosingInstance { get; }
500	    }
501	}

