22	using System.Data.Common;
23	
24	using Microsoft.Extensions.Logging;
25	
26	using Quartz.Diagnostics;
27	using Quartz.Spi;
28	
29	using LogLevel = Microsoft.Extensions.Logging.LogLevel;
30	
31	namespace Quartz.Core;
32	
33	/// <summary>
34	/// The thread responsible for performing the work of firing <see cref="ITrigger" />
35	/// s that are registered with the <see cref="QuartzScheduler" />.
36	/// </summary>
37	/// <seealso cref="QuartzScheduler" />
38	/// <seealso cref="IJob" />
39	/// <seealso cref="ITrigger" />
40	/// <author>James House</author>
41	/// <author>Marko Lahma (.NET)</author>
42	internal sealed class QuartzSchedulerThread
43	{
44	    private readonly ILogger logger;
45	    private readonly QuartzScheduler qs;
46	    private readonly QuartzSchedulerResources qsRsrcs;
47	    private readonly int idleWaitVariableness;
48	    private readonly Lock sigLock = new();
49	    private readonly SemaphoreSlim schedulingChangeSignal = new(0, 1);
50	    private readonly SemaphoreSlim pauseSignal = new(0, 1);
51	
52	    private bool signaled;
53	    private DateTimeOffset? signaledNextFireTimeUtc;
54	    private volatile bool paused;
55	    private volatile bool halted;
56	
57	    private CancellationTokenSource cancellationTokenSource = null!;
58	    private Task task = null!;
59	
60	    private const int PausedWaitCheckIntervalMs = 1000;
61	
62	    /// <summary>
63	    /// Gets the randomized idle wait time.
64	    /// </summary>
65	    /// <value>The randomized idle wait time.</value>
66	    private TimeSpan GetRandomizedIdleWaitTime()
67	    {
68	        return qsRsrcs.IdleWaitTime - TimeSpan.FromMilliseconds(QuartzRandom.Next(idleWaitVariableness));
69	    }
70	
71	    /// <summary>
72	    /// Gets a value indicating whether this <see cref="QuartzSchedulerThread"/> is paused.
73	    /// </summary>
74	    /// <value><c>true</c> if paused; otherwise, <c>false</c>.</value>
75	    internal bool Paused => paused;
76	
77	    /// <summary>
78	    /// Gets a value indicating whether this <see cref="QuartzSchedulerThread"/> is stopped.
79	    /// </summary>
80	    /// <value>
81	    /// <see langword="true"/> if stopped; otherwise, <see langword="false"/>.
82	    /// </value>
83	    internal bool Halted => halted;
84	
85	    /// <summary>
86	    /// Gets the maximum number of milliseconds to subtract from <see cref="QuartzSchedulerResources.IdleWaitTime"/>
87	    /// to randomize how long the scheduler should wait before checking again when there is no current trigger to
88	    /// fire.
89	    /// </summary>
90	    /// <value>
91	    /// The maximum number of milliseconds to subtract from <see cref="QuartzSchedulerResources.IdleWaitTime"/> to
92	    /// randomize how long the scheduler should wait before checking again when there is no current trigger to fire.
93	    /// </value>
94	    internal int IdleWaitVariableness => idleWaitVariableness;
95	
96	    /// <summary>
97	    /// Construct a new <see cref="QuartzSchedulerThread" /> for the given
98	    /// <see cref="QuartzScheduler" /> as a non-daemon <see cref="Thread" />
99	    /// with normal priority.
100	    /// </summary>
101	    /// <param name="qs">The scheduler.</param>
102	    /// <param name="qsRsrcs">The resources.</param>
103	    internal QuartzSchedulerThread(QuartzScheduler qs, QuartzSchedulerResources qsRsrcs)
104	    {
105	        this.logger = LogProvider.CreateLogger<QuartzSchedulerThread>();
106	        this.qs = qs;
107	        this.qsRsrcs = qsRsrcs;
108	        idleWaitVariableness = (int) (qsRsrcs.IdleWaitTime.TotalMilliseconds * 0.2);
109	
110	        // start the underlying thread, but put this object into the 'paused'
111	        // state
112	        // so processing doesn't start yet...
113	        paused = true;
114	        halted = false;
115	    }
116	
117	    /// <summary>
118	    /// Signals the main processing loop to pause at the next possible point.
119	    /// </summary>
120	    internal void TogglePause(bool pause)
121	    {
122	        lock (sigLock)
123	        {
124	            paused = pause;
125	        }
126	
127	        if (pause)
128	        {
129	            SignalSchedulingChange(SchedulerConstants.SchedulingSignalDateTime);
130	        }
131	        else
132	        {
133	            try
134	            {
135	                pauseSignal.Release();
136	            }
137	            catch (SemaphoreFullException)
138	            {
139	            }
140	        }
141	    }
142	
143	    /// <summary>
144	    /// Signals the main processing loop to stop at the next possible point.
145	    /// </summary>
146	    internal async Task Halt(bool wait)
147	    {
148	        lock (sigLock)
149	        {
150	            halted = true;
151	        }
152	
153	        // Release the pause signal in case Run() is blocked in the paused wait loop.
154	        // CancellationToken cancellation will also interrupt any pending WaitAsync calls.
155	        try
156	        {
157	            pauseSignal.Release();
158	        }
159	        catch (SemaphoreFullException)
160	        {
161	        }
162	
163	        await cancellationTokenSource.CancelAsync().ConfigureAwait(false);
164	
165	        if (wait)
166	        {
167	            try
168	            {
169	                await task.ConfigureAwait(false);
170	            }
171	            catch (OperationCanceledException)
172	            {
173	            }
174	        }
175	    }
176	
177	    /// <summary>
178	    /// Signals the main processing loop that a change in scheduling has been
179	    /// made - in order to interrupt any sleeping that may be occurring while
180	    /// waiting for the fire time to arrive.
181	    /// </summary>
182	    /// <param name="candidateNewNextFireTimeUtc">
183	    /// the time when the newly scheduled trigger
184	    /// will fire.  If this method is being called do to some other even (rather
185	    /// than scheduling a trigger), the caller should pass null.
186	    /// </param>
187	    public void SignalSchedulingChange(DateTimeOffset? candidateNewNextFireTimeUtc)
188	    {
189	        lock (sigLock)
190	        {
191	            signaled = true;
192	            signaledNextFireTimeUtc = candidateNewNextFireTimeUtc;
193	        }
194	
195	        try
196	        {
197	            schedulingChangeSignal.Release();
198	        }
199	        catch (SemaphoreFullException)
200	        {
201	        }
202	    }
203	
204	    public void ClearSignaledSchedulingChange()
205	    {
206	        lock (sigLock)
207	        {
208	            signaled = false;
209	            signaledNextFireTimeUtc = SchedulerConstants.SchedulingSignalDateTime;
210	        }
211	    }
212	
213	    public bool IsScheduleChanged()
214	    {
215	        lock (sigLock)
216	        {
217	            return signaled;
218	        }
219	    }
220	
221	    public DateTimeOffset? GetSignaledNextFireTimeUtc()
222	    {
223	        lock (sigLock)
224	        {
225	            return signaledNextFireTimeUtc;
226	        }
227	    }
228	
229	    /// <summary>
230	    /// The main processing loop of the <see cref="QuartzSchedulerThread" />.
231	    /// </summary>
232	    public async Task Run()
233	    {
234	        int acquiresFailed = 0;
235	        Context.CallerId.Value = Guid.NewGuid();
236	
237	        while (!halted)
238	        {
239	            cancellationTokenSource.Token.ThrowIfCancellationRequested();
240	            try
241	            {
242	                // check if we're supposed to pause...
243	                while (paused && !halted)
244	                {
245	                    try
246	                    {
247	                        // wait until togglePause(false) is called...
248	                        await pauseSignal.WaitAsync(PausedWaitCheckIntervalMs, cancellationTokenSource.Token).ConfigureAwait(false);
249	                    }
250	                    catch (OperationCanceledException)
251	                    {
252	                        break;
253	                    }
254	
255	                    // reset failure counter when paused, so that we don't
256	                    // wait again after unpausing
257	                    acquiresFailed = 0;
258	                }
259	
260	                if (halted)
261	                {
262	                    break;
263	                }
264	
265	                // wait a bit, if reading from job store is consistently
266	                // failing (e.g. DB is down or restarting)..
267	                if (acquiresFailed > 1)
268	                {
269	                    try
270	                    {
271	                        var delay = ComputeDelayForRepeatedErrors(qsRsrcs.JobStore, acquiresFailed);
272	                        await Task.Delay(delay).ConfigureAwait(false);
273	                    }
274	                    catch
275	                    {
276	                    }
277	                }
278	
279	                cancellationTokenSource.Token.ThrowIfCancellationRequested();
280	                int availThreadCount = qsRsrcs.ThreadPool.BlockForAvailableThreads();
281	                if (halted)
282	                {
283	                    break;
284	                }
285	                if (availThreadCount > 0)
286	                {
287	                    List<IOperableTrigger> triggers;
288	
289	                    DateTimeOffset now = qsRsrcs.TimeProvider.GetUtcNow();
290	
291	                    ClearSignaledSchedulingChange();
292	                    try
293	                    {
294	                        var noLaterThan = now + qsRsrcs.IdleWaitTime;
295	                        var maxCount = Math.Min(availThreadCount, qsRsrcs.MaxBatchSize);
296	                        triggers = new List<IOperableTrigger>(await qsRsrcs.JobStore.AcquireNextTriggers(noLaterThan, maxCount, qsRsrcs.BatchTimeWindow, CancellationToken.None).ConfigureAwait(false));
297	                        acquiresFailed = 0;
298	                        if (logger.IsEnabled(LogLevel.Debug))
299	                        {
300	                            logger.LogDebug("Batch acquisition of {TriggerCount} triggers", triggers.Count);
301	                        }
302	                    }
303	                    catch (JobPersistenceException jpe)
304	                    {
305	                        if (acquiresFailed == 0)
306	                        {
307	                            var msg = "An error occurred while scanning for the next trigger to fire.";
308	                            await qs.NotifySchedulerListenersError(msg, jpe, CancellationToken.None).ConfigureAwait(false);
309	                        }
310	
311	                        if (acquiresFailed < int.MaxValue)
312	                        {
313	                            acquiresFailed++;
314	                        }
315	
316	                        continue;
317	                    }
318	                    catch (Exception e)
319	                    {
320	                        if (acquiresFailed == 0)
321	                        {
322	                            logger.LogError(e, "quartzSchedulerThreadLoop: RuntimeException {Message}", e.Message);
323	                        }
324	                        if (acquiresFailed < int.MaxValue)
325	                        {
326	                            acquiresFailed++;
327	                        }
328	                        continue;
329	                    }
330	
331	                    if (triggers is not null && triggers.Count > 0)
332	                    {
333	                        now = qsRsrcs.TimeProvider.GetUtcNow();
334	                        DateTimeOffset triggerTime = triggers[0].GetNextFireTimeUtc()!.Value;
335	                        TimeSpan timeUntilTrigger = triggerTime - now;
336	
337	                        while (timeUntilTrigger > TimeSpan.Zero)
338	                        {
339	                            if (await ReleaseIfScheduleChangedSignificantly(triggers, triggerTime).ConfigureAwait(false))
340	                            {
341	                                break;
342	                            }
343	                            if (halted)
344	                            {
345	                                break;
346	                            }
347	                            if (!IsCandidateNewTimeEarlierWithinReason(triggerTime, false))
348	                            {
349	                                // we could have blocked a long while
350	                                // on 'synchronize', so we must recompute
351	                                now = qsRsrcs.TimeProvider.GetUtcNow();
352	                                timeUntilTrigger = triggerTime - now;
353	                                if (timeUntilTrigger > TimeSpan.Zero)
354	                                {
355	                                    try
356	                                    {
357	                                        // Cap the wait time to recover from system clock backward jumps.
358	                                        // The outer while loop recomputes timeUntilTrigger from the current clock after each wait.
359	                                        var waitTime = timeUntilTrigger < qsRsrcs.IdleWaitTime ? timeUntilTrigger : qsRsrcs.IdleWaitTime;
360	                                        await schedulingChangeSignal.WaitAsync(waitTime, cancellationTokenSource.Token).ConfigureAwait(false);
361	                                    }
362	                                    catch (OperationCanceledException)
363	                                    {
364	                                        break;
365	                                    }
366	                                }
367	                            }
368	                            if (halted)
369	                            {
370	                                break;
371	                            }
372	                            if (await ReleaseIfScheduleChangedSignificantly(triggers, triggerTime).ConfigureAwait(false))
373	                            {
374	                                break;
375	                            }
376	                            now = qsRsrcs.TimeProvider.GetUtcNow();
377	                            timeUntilTrigger = triggerTime - now;
378	                        }
379	
380	                        // this happens if releaseIfScheduleChangedSignificantly decided to release triggers
381	                        if (triggers.Count == 0)
382	                        {
383	                            continue;
384	                        }
385	
386	                        // set triggers to 'executing'
387	                        List<TriggerFiredResult> bndles = new List<TriggerFiredResult>();
388	
389	                        bool goAhead = !halted;
390	
391	                        if (goAhead)
392	                        {
393	                            try
394	                            {
395	                                var res = await qsRsrcs.JobStore.TriggersFired(triggers, CancellationToken.None).ConfigureAwait(false);
396	                                if (res is not null)
397	                                {
398	                                    bndles = res.ToList();
399	                                }
400	                            }
401	                            catch (SchedulerException se)
402	                            {
403	                                var msg = "An error occurred while firing triggers '" + triggers + "'";
404	                                await qs.NotifySchedulerListenersError(msg, se, CancellationToken.None).ConfigureAwait(false);
405	                                // QTZ-179 : a problem occurred interacting with the triggers from the db
406	                                // we release them and loop again
407	                                foreach (IOperableTrigger t in triggers)
408	                                {
409	                                    await qsRsrcs.JobStore.ReleaseAcquiredTrigger(t, CancellationToken.None).ConfigureAwait(false);
410	                                }
411	                                continue;
412	                            }
413	                        }
414	                        else
415	                        {
416	                            // Scheduler is shutting down - release acquired triggers
417	                            // so they don't remain stuck in ACQUIRED state
418	                            foreach (IOperableTrigger t in triggers)
419	                            {
420	                                await qsRsrcs.JobStore.ReleaseAcquiredTrigger(t, CancellationToken.None).ConfigureAwait(false);
421	                            }
422	                            continue;
423	                        }
424	
425	                        for (int i = 0; i < bndles.Count; i++)
426	                        {
427	                            TriggerFiredResult result = bndles[i];
428	                            var bndle = result.TriggerFiredBundle;
429	                            var exception = result.Exception;
430	
431	                            IOperableTrigger trigger = triggers[i];
432	                            // TODO SQL exception?
433	                            if (exception is not null && (exception is DbException || exception.InnerException is DbException))
434	                            {
435	                                logger.LogError(exception, "DbException while firing trigger {Trigger}", trigger);
436	                                await qsRsrcs.JobStore.ReleaseAcquiredTrigger(trigger, CancellationToken.None).ConfigureAwait(false);
437	                                continue;
438	                            }
439	
440	                            // it's possible to get 'null' if the triggers was paused,
441	                            // blocked, or other similar occurrences that prevent it being
442	                            // fired at this time...  or if the scheduler was shutdown (halted)
443	                            if (bndle is null)
444	                            {
445	                                await qsRsrcs.JobStore.ReleaseAcquiredTrigger(trigger, CancellationToken.None).ConfigureAwait(false);
446	                                continue;
447	                            }
448	
449	                            // TODO: improvements:
450	                            //
451	                            // 2- make sure we can get a job runshell before firing trigger, or
452	                            //   don't let that throw an exception (right now it never does,
453	                            //   but the signature says it can).
454	                            // 3- acquire more triggers at a time (based on num threads available?)
455	
456	                            JobRunShell shell;
457	                            try
458	                            {
459	                                shell = qsRsrcs.JobRunShellFactory.CreateJobRunShell(bndle);
460	                                await shell.Initialize(qs, CancellationToken.None).ConfigureAwait(false);
461	                            }
462	                            catch (SchedulerException se)
463	                            {
464	                                if (se.InnerException is ObjectDisposedException or OperationCanceledException || cancellationTokenSource.Token.IsCancellationRequested)
465	                                {
466	                                    // the scheduler is being stopped, so we can't run the job
467	                                    // use TriggeredJobComplete to properly unblock other triggers
468	                                    // for DisallowConcurrentExecution jobs (TriggersFired already ran)
469	                                    await qsRsrcs.JobStore.TriggeredJobComplete(trigger, bndle.JobDetail, SchedulerInstruction.NoInstruction, CancellationToken.None).ConfigureAwait(false);
470	                                }
471	                                else
472	                                {
473	                                    // we consider this a serious error and expect that job instantiation will never succeed in the future either
474	                                    await qsRsrcs.JobStore.TriggeredJobComplete(trigger, bndle.JobDetail, SchedulerInstruction.SetAllJobTriggersError, CancellationToken.None).ConfigureAwait(false);
475	                                }
476	
477	                                continue;
478	                            }
479	
480	                            var threadPoolRunResult = qsRsrcs.ThreadPool.RunInThread(() => shell.Run(CancellationToken.None));
481	                            if (!threadPoolRunResult)
482	                            {
483	                                // Check if the scheduler is being shutdown
484	                                if (halted || cancellationTokenSource.Token.IsCancellationRequested)
485	                                {
486	                                    // Scheduler is shutting down, complete the trigger gracefully
487	                                    // Use TriggeredJobComplete to properly unblock other triggers
488	                                    // for DisallowConcurrentExecution jobs (TriggersFired already ran)
489	                                    logger.LogDebug("ThreadPool.RunInThread() returned false due to scheduler shutdown, completing trigger");
490	                                    await qsRsrcs.JobStore.TriggeredJobComplete(trigger, bndle.JobDetail, SchedulerInstruction.NoInstruction, CancellationToken.None).ConfigureAwait(false);
491	                                }
492	                                else
493	                                {
494	                                    // this case should never happen, as it is indicative of a bug in the thread pool or
495	                                    // a thread pool being used concurrently - which the docs say not to do...
496	                                    logger.LogError("ThreadPool.RunInThread() returned false");
497	                                    await qsRsrcs.JobStore.TriggeredJobComplete(trigger, bndle.JobDetail, SchedulerInstruction.SetAllJobTriggersError, CancellationToken.None).ConfigureAwait(false);
498	                                }
499	                            }
500	                        }
501	
502	                        continue; // while (!halted)
503	                    }
504	                }
505	                else // if(availThreadCount > 0)
506	                {
507	                    continue;
508	                    // while (!halted)
509	                }
510	
511	                TimeSpan timeUntilContinue = GetRandomizedIdleWaitTime();
512	                if (!halted && !IsScheduleChanged())
513	                {
514	                    try
515	                    {
516	                        // QTZ-336 A job might have been completed in the mean time and we might have
517	                        // missed the scheduled changed signal by not waiting for the notify() yet
518	                        // Check that before waiting for too long in case this very job needs to be
519	                        // scheduled very soon
520	                        await schedulingChangeSignal.WaitAsync(timeUntilContinue, cancellationTokenSource.Token).ConfigureAwait(false);
521	                    }
522	                    catch (OperationCanceledException)
523	                    {
524	                    }
525	                }
526	            }
527	            catch (Exception re)
528	            {
529	                logger.LogError(re, "Runtime error occurred in main trigger firing loop.");
530	            }
531	        } // while (!halted)
532	    }
533	
534	    private static readonly TimeSpan minDelay = TimeSpan.FromMilliseconds(20);
535	    private static readonly TimeSpan maxDelay = TimeSpan.FromMinutes(10);
536	
537	    private static TimeSpan ComputeDelayForRepeatedErrors(IJobStore jobStore, int acquiresFailed)
538	    {
539	        var delay = TimeSpan.FromMilliseconds(100);
540	        try
541	        {
542	            delay = jobStore.GetAcquireRetryDelay(acquiresFailed);
543	        }
544	        catch
545	        {
546	            // we're trying to be useful in case of error states, not cause
547	            // additional errors..
548	        }
549	
550	        // sanity check per getAcquireRetryDelay specification
551	        if (delay < minDelay)
552	        {
553	            delay = minDelay;
554	        }
555	
556	        if (delay > maxDelay)
557	        {
558	            delay = maxDelay;
559	        }
560	
561	        return delay;
562	    }
563	
564	    private async ValueTask<bool> ReleaseIfScheduleChangedSignificantly(List<IOperableTrigger> triggers, DateTimeOffset triggerTime)
565	    {
566	        if (IsCandidateNewTimeEarlierWithinReason(triggerTime, true))
567	        {
568	            foreach (IOperableTrigger trigger in triggers)
569	            {
570	                // above call does a clearSignaledSchedulingChange()
571	                await qsRsrcs.JobStore.ReleaseAcquiredTrigger(trigger).ConfigureAwait(false);
572	            }
573	            triggers.Clear();
574	            return true;
575	        }
576	
577	        return false;
578	    }
579	
580	    private bool IsCandidateNewTimeEarlierWithinReason(DateTimeOffset oldTimeUtc, bool clearSignal)
581	    {
582	        // So here's the deal: We know due to being signaled that 'the schedule'
583	        // has changed.  We may know (if getSignaledNextFireTime() != DateTimeOffset.MinValue) the
584	        // new earliest fire time.  We may not (in which case we will assume
585	        // that the new time is earlier than the trigger we have acquired).
586	        // In either case, we only want to abandon our acquired trigger and
587	        // go looking for a new one if "it's worth it".  It's only worth it if
588	        // the time cost incurred to abandon the trigger and acquire a new one
589	        // is less than the time until the currently acquired trigger will fire,
590	        // otherwise we're just "thrashing" the job store (e.g. database).
591	        //
592	        // So the question becomes when is it "worth it"?  This will depend on
593	        // the job store implementation (and of course the particular database
594	        // or whatever behind it).  Ideally we would depend on the job store
595	        // implementation to tell us the amount of time in which it "thinks"
596	        // it can abandon the acquired trigger and acquire a new one.  However
597	        // we have no current facility for having it tell us that, so we make
598	        // a somewhat educated but arbitrary guess.
599	
600	        lock (sigLock)
601	        {
602	            if (!IsScheduleChanged())
603	            {
604	                return false;
605	            }
606	
607	            bool earlier = false;
608	
609	            if (!GetSignaledNextFireTimeUtc().HasValue)
610	            {
611	                earlier = true;
612	            }
613	            else if (GetSignaledNextFireTimeUtc()!.Value < oldTimeUtc)
614	            {
615	                earlier = true;
616	            }
617	
618	            if (earlier)
619	            {
620	                // so the new time is considered earlier, but is it enough earlier?
621	                TimeSpan diff = oldTimeUtc - qsRsrcs.TimeProvider.GetUtcNow();
622	                if (diff < (qsRsrcs.JobStore.SupportsPersistence ? TimeSpan.FromMilliseconds(70) : TimeSpan.FromMilliseconds(7)))
623	                {
624	                    earlier = false;
625	                }
626	            }
627	
628	            if (clearSignal)
629	            {
630	                ClearSignaledSchedulingChange();
631	            }
632	
633	            return earlier;
634	        }
635	    }
636	
637	    public void Start()
638	    {
639	        cancellationTokenSource = new CancellationTokenSource();
640	        task = Task.Factory.StartNew(
641	            static state => ((QuartzSchedulerThread) state!).Run(),
642	            this,
643	            cancellationTokenSource.Token,
644	            TaskCreationOptions.LongRunning | TaskCreationOptions.DenyChildAttach,
645	            TaskScheduler.Default
646	        ).Unwrap();
647	    }
648	
649	    public async Task Shutdown()
650	    {
651	        cancellationTokenSource.Cancel();
652	        try
653	        {
654	            await task.ConfigureAwait(false);
655	        }
656	        catch (OperationCanceledException)
657	        {
658	        }
659	    }
660	}

