using Quartz.Core;
using Quartz.Impl;
using Quartz.Impl.Triggers;
using Quartz.Spi;

namespace Quartz.Tests.Unit.Core;

[TestFixture]
public class JobRunShellAsyncLocalTest
{
    private static readonly AsyncLocal<string> CurrentTenant = new();

    public class TenantContextJobFactory : IJobFactory
    {
        public IJob NewJob(TriggerFiredBundle bundle, IScheduler scheduler)
        {
            // Set an AsyncLocal value during job creation
            CurrentTenant.Value = bundle.JobDetail.JobDataMap.GetString("TenantId");
            return new TenantAwareJob();
        }

        public ValueTask ReturnJob(IJob job)
        {
            return default;
        }
    }

    [DisallowConcurrentExecution]
    public class TenantAwareJob : IJob
    {
        public ValueTask Execute(IJobExecutionContext context)
        {
            // The AsyncLocal should be accessible here during Execute
            Assert.That(CurrentTenant.Value, Is.EqualTo("Tenant-123"),
                "AsyncLocal value set during IJobFactory.NewJob should be accessible during IJob.Execute");
            return default;
        }
    }

    [Test]
    public async Task AsyncLocalValuesShouldFlowFromJobFactoryToJobExecution()
    {
        var props = new System.Collections.Specialized.NameValueCollection
        {
            ["quartz.scheduler.instanceName"] = "AsyncLocalTestScheduler"
        };

        var schedulerFactory = new StdSchedulerFactory(props);
        var scheduler = await schedulerFactory.GetScheduler();
        scheduler.JobFactory = new TenantContextJobFactory();

        try
        {
            var jobDetail = JobBuilder.Create<TenantAwareJob>()
                .WithIdentity("testJob", "testGroup")
                .UsingJobData("TenantId", "Tenant-123")
                .Build();

            var trigger = (IOperableTrigger)TriggerBuilder.Create()
                .WithIdentity("testTrigger", "testGroup")
                .StartNow()
                .Build();

            await scheduler.ScheduleJob(jobDetail, trigger);
            await scheduler.Start();

            // Wait for the job to fire
            await Task.Delay(5000);

            await scheduler.Shutdown(waitForJobsToComplete: true);
        }
        catch
        {
            if (!scheduler.IsShutdown)
            {
                await scheduler.Shutdown(waitForJobsToComplete: true);
            }
            throw;
        }
    }
}

