    public async Task TestRunInThreadPreservesExecutionContext()
    {
        // Test that the thread pool RunInThread preserves ExecutionContext
        var threadPool = new DefaultThreadPool();
        threadPool.Initialize();

        var taskCompletionSource = new TaskCompletionSource<bool>();
        string valueSetDuringTask = null;

        threadPool.RunInThread(async () =>
        {
            CurrentTenant.Value = "TestValue";
            valueSetDuringTask = CurrentTenant.Value;
            taskCompletionSource.SetResult(true);
            await Task.CompletedTask;
        });

        await taskCompletionSource.Task;

        Assert.That(valueSetDuringTask, Is.EqualTo("TestValue"));

        threadPool.Shutdown(waitForJobsToComplete: true);
    }
}

