    public void AsyncLocalValueSetInAsyncMethodFlowsToCaller_SyncCompletion()
    {
        async Task SetAsyncLocal()
        {
            // Synchronously complete - no actual await
            CurrentTenant.Value = "TestValue";
            await Task.CompletedTask;
        }

        async Task RunTest()
        {
            await SetAsyncLocal();
            Assert.That(CurrentTenant.Value, Is.EqualTo("TestValue"),
                "AsyncLocal should be preserved when set in async method that completes synchronously");
        }

        RunTest().GetAwaiter().GetResult();
    }

    [Test]
    public async Task AsyncLocalValueSetInAsyncMethodFlowsToCaller_RealAwait()
    {
        async Task SetAsyncLocal()
        {
            await Task.Yield(); // Real async completion
            CurrentTenant.Value = "TestValue";
        }

        await SetAsyncLocal();
        Assert.That(CurrentTenant.Value, Is.EqualTo("TestValue"),
            "AsyncLocal should be preserved when set in async method that completes asynchronously");
    }

