            await SetAsyncLocal();
            tcs.SetResult(CurrentTenant.Value);
        });

        var result = await tcs.Task;
        Assert.That(result, Is.EqualTo("TestValue"),
            "AsyncLocal set in inner async method should be visible in outer lambda");

        threadPool.Shutdown(waitForJobsToComplete: true);
