                                }
                                catch (Exception ex) when (ex is not OperationCanceledException)
                                {
                                    // If Initialize fails, we need to notify the job store
                                    SchedulerException se = ex as SchedulerException
                                        ?? new SchedulerException($"Problem instantiating job '{bndle.JobDetail.JobType.FullName}': {ex.Message}", ex);

                                    if (se.InnerException is ObjectDisposedException or OperationCanceledException || cancellationTokenSource.Token.IsCancellationRequested)
                                    {
                                        await qsRsrcs.JobStore.TriggeredJobComplete(trigger, bndle.JobDetail, SchedulerInstruction.NoInstruction, CancellationToken.None).ConfigureAwait(false);
                                    }
                                    else
                                    {
                                        await qsRsrcs.JobStore.TriggeredJobComplete(trigger, bndle.JobDetail, SchedulerInstruction.SetAllJobTriggersError, CancellationToken.None).ConfigureAwait(false);
                                    }

                                    await qs.NotifySchedulerListenersError($"An error occurred instantiating job to be executed. job= '{bndle.JobDetail.Key}, message={se.Message}'", se, CancellationToken.None).ConfigureAwait(false);
                                    return;
                                }

                                await shell.Run(CancellationToken.None).ConfigureAwait(false);
                            });

