// Run Initialize and Run together in the thread pool task so that
                            // any ExecutionContext (e.g. AsyncLocal<T>) values set during
                            // IJobFactory.NewJob (called from Initialize) flow into IJob.Execute
                            // (called from Run).
                            // We call Initialize synchronously (via GetAwaiter().GetResult()) because it
                            // completes synchronously in the normal case (no actual await happens),
                            // and using await here would cause the async state machine to capture
                            // and restore the ExecutionContext, losing any AsyncLocal<T> changes
                            // made during NewJob.
                            // This is safe because we are running on a thread pool thread with no
                            // SynchronizationContext, so there's no risk of deadlock.
                            var threadPoolRunResult = qsRsrcs.ThreadPool.RunInThread(() =>
                            {
                                try
                                {
                                    shell.Initialize(qs, CancellationToken.None).GetAwaiter().GetResult();
                                }
                                catch (SchedulerException se)
                                {
                                    // Handle errors by completing the trigger appropriately
                                    // We cannot await here since we're in a sync context,
                                    // so we just let the exception propagate and handle it below.
                                    throw;
                                }
                                catch (Exception e)
                                {
                                    SchedulerException se = new SchedulerException($"Problem instantiating type '{bndle.JobDetail.JobType.FullName}: {e.Message}'", e);
                                    throw se;
                                }

                                return shell.Run(CancellationToken.None);
                            });

