                            // Use InitializeAndRun to ensure that IJobFactory.NewJob and IJob.Execute
                            // run in the same async execution context, preserving AsyncLocal<T> values
                            // set during NewJob.
                            var threadPoolRunResult = qsRsrcs.ThreadPool.RunInThread(() =>
                                shell.InitializeAndRun(qs, CancellationToken.None));

