using Quartz.Simpl;

namespace Quartz.Tests.Unit.Core;

[TestFixture]
public class AsyncLocalExecutionContextTest
{
    private static readonly AsyncLocal<string> MyAsyncLocal = new();

    [Test]
    public async Task AsyncLocalSetInSyncCompletingAsyncMethod_FlowsToCaller()
    {
        async Task SetValue()
        {
            MyAsyncLocal.Value = "TestValue";
            // no await - completes synchronously
        }

        await SetValue();
        Assert.That(MyAsyncLocal.Value, Is.EqualTo("TestValue"),
            "AsyncLocal set in synchronously-completing async method should be visible");
    }

    [Test]
    public async Task AsyncLocalSetInSyncCompletingAsyncMethod_WithConfigureAwaitFalse_FlowsToCaller()
    {
        async Task SetValue()
        {
            MyAsyncLocal.Value = "TestValue";
            await Task.CompletedTask.ConfigureAwait(false);
            // sync completion
        }

        await SetValue().ConfigureAwait(false);
        Assert.That(MyAsyncLocal.Value, Is.EqualTo("TestValue"),
            "AsyncLocal with ConfigureAwait(false) should still flow");
    }

    [Test]
    public async Task AsyncLocalSetBeforeAwaitInSameMethod_VisibleAfterAwait()
    {
        MyAsyncLocal.Value = "Before";
        await Task.Yield();
        Assert.That(MyAsyncLocal.Value, Is.EqualTo("Before"),
            "AsyncLocal set before await should be visible after await");
    }

    [Test]
    public async Task AsyncLocalSetInNestedAsyncMethod_VisibleToCaller()
    {
        async Task SetValue()
        {
            await Task.Yield(); // real async boundary
            MyAsyncLocal.Value = "TestValue";
        }

        await SetValue();
        Assert.That(MyAsyncLocal.Value, Is.EqualTo("TestValue"),
            "AsyncLocal set in nested async method with real await should be visible to caller");
    }

    [Test]
    public async Task AsyncLocalSetInSyncCompletingMethodInTaskQueue_FlowsToCaller()
    {
        var tcs = new TaskCompletionSource<string>();

        async Task SetValue()
        {
            MyAsyncLocal.Value = "TestValue";
            await Task.CompletedTask;
        }

        var threadPool = new DefaultThreadPool();
        threadPool.Initialize();

        threadPool.RunInThread(async () =>
        {
            await SetValue();
            tcs.SetResult(MyAsyncLocal.Value);
        });

        var result = await tcs.Task;
        Assert.That(result, Is.EqualTo("TestValue"),
            "AsyncLocal set in sync-completing method in RunInThread");

        threadPool.Shutdown(waitForJobsToComplete: true);
    }

    [Test]
    public async Task AsyncLocalSetInSyncCompletingMethodInNewTask()
    {
        var tcs = new TaskCompletionSource<string>();

        async Task SetValue()
        {
            MyAsyncLocal.Value = "TestValue";
            await Task.CompletedTask;
        }

        // This uses new Task() which captures ExecutionContext
        var task = new Task<Task>(async () =>
        {
            await SetValue();
            tcs.SetResult(MyAsyncLocal.Value);
        });
        task.Start(TaskScheduler.Default);

        var result = await tcs.Task;
        Assert.That(result, Is.EqualTo("TestValue"),
            "AsyncLocal set in sync-completing method in new Task");

        await task.Unwrap();
    }
}

