        {
            MyAsyncLocal.Value = "TestValue";
            // no await - completes synchronously
        }

        await SetValue();
        Assert.That(MyAsyncLocal.Value, Is.EqualTo("TestValue"),
            "AsyncLocal set in synchronously-completing async method should be visible");
    }

    [Test]
    public async Task AsyncLocalSetInSyncCompletingAsyncMethod_WithConfigureAwaitFalse_FlowsToCaller()
    {
        async Task SetValue()
        {
            MyAsyncLocal.Value = "TestValue";
            await Task.CompletedTask.ConfigureAwait(false);
