        }

        await SetValue().ConfigureAwait(false);
        Assert.That(MyAsyncLocal.Value, Is.EqualTo("TestValue"),
            "AsyncLocal with ConfigureAwait(false) should still flow");
    }

    [Test]
    public async Task AsyncLocalSetBeforeAwaitInSameMethod_VisibleAfterAwait()
    {
