        await Task.Yield();
        Assert.That(MyAsyncLocal.Value, Is.EqualTo("Before"),
            "AsyncLocal set before await should be visible after await");
    }

    [Test]
    public async Task AsyncLocalSetInNestedAsyncMethod_VisibleToCaller()
    {
        async Task SetValue()
