            tcs.SetResult(MyAsyncLocal.Value);
        });

        var result = await tcs.Task;
        Assert.That(result, Is.EqualTo("TestValue"),
            "AsyncLocal set in sync-completing method in RunInThread");

        threadPool.Shutdown(waitForJobsToComplete: true);
    }

